const PRIME_64 = 1099511628211

const breadUp = (val) => {
  let temp = val
  temp <<= BigInt(18)
  val -= temp
  temp <<= BigInt(33)
  val -= temp
  temp <<= BigInt(3)
  val += temp
  temp <<= BigInt(3)
  val -= temp
  temp <<= BigInt(4)
  val += temp
  temp <<= BigInt(2)
  val += temp
  val = val >> BigInt(1)
  return val & BigInt('9223372036854775807')
}

const fnv = (data) => {
  let hash = BigInt('14695981039346656037')
  const prime = BigInt(PRIME_64)

  for (let i = 0; i < data.length; i++) {
    hash = (hash * prime) % BigInt('18446744073709551616')
    hash ^= BigInt(data.charCodeAt(i))
  }

  return hash
}

module.exports.logIdHash = function logIdHash(logId) {
  return breadUp(fnv(logId))
}
